import React from 'react';
import './Services.css';

const SERVICES = [
  { name: 'YouTube Video Editing', price: 'From $300' },
  { name: 'Color Grading', price: 'From $240' },
  { name: 'Short-Form Social Cuts', price: 'From $180' },
  { name: 'Brand Campaign Editing', price: 'From $600' },
  { name: 'Full Post-Production Package', price: 'Custom Quote' },
];

export default function Services() {
  return (
    <section className="section reveal-on-scroll" id="services">
      <div className="section-inner">
        <p className="section-label">Services</p>
        <h2 className="section-title">Precision Editing, Clear Pricing</h2>

        <div className="services-list">
          {SERVICES.map((service) => (
            <div className="service-row" key={service.name}>
              <span className="service-name">{service.name}</span>
              <span className="service-price">{service.price}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
